python3 << 'EOF'
text = """When droplets hang in humid air, they act like tiny spheres bending rays through angles according to Snell's law of refractive index. Each droplet sends rays along paths, spreading them into a circular arc visible to observers with backs to the Sun. The band looks curved because we only see droplets in a specific cone of view. Rays bend by different amounts, creating ordered bands from outer red to inner violet. Every viewer sees their own beautiful unique ring"""

# Check for forbidden substrings more carefully
forbidden = ['prism', 'newton', 'colour', 'color', 'spectrum', 'wavelength', 'nm', 'iris', 'sun shower', 'god', 'pot of gold', 'rainbow', 'light']
text_lower = text.lower()
print("Checking forbidden substrings:")
for f in forbidden:
    if f in text_lower:
        print(f"FOUND FORBIDDEN: '{f}'")
    else:
        print(f"OK: '{f}'")

# Check the mandatory ones
print("\nChecking mandatory substrings:")
mandatory = [('Snell', 'Snell'), ('refractive index', 'refractive index'), ('cone of view', 'cone of view'), ('circular arc', 'circular arc')]
for m, check in mandatory:
    if check in text:
        print(f"Found: '{m}'")
    else:
        print(f"MISSING: '{m}'")

# Also verify no 'light' as substring
print("\n'l' 'li' 'lig' 'ligh' 'light' check:")
for suffix in ['l', 'li', 'lig', 'ligh', 'light']:
    if suffix in text_lower:
        print(f"Found: {suffix}")
EOF
